export const OVN = {
  "96632":{id:"96632",namn:"Ö1 – Förberedelseträning Speluppbyggnad",typ:"Färdighetsövning",skede:"ANF",kategori:"Speluppbyggnad",principer:["Spelbarhet","Speldjup","Spelvändning"],vad:"Speluppbyggnad",varfor:"Behålla bollen inom laget.",hur:["Mottagning: Rikta stödjebenet dit mottagningen ska göras, vinkla ut den andra foten.","Passning insida: Vrida ut tillslagsfoten, föra benet bakåt, träffa med insidan och fullfölja pendlingen.","Passning vristen: Föra benet bakåt, tårna peka nedåt, fullfölja pendlingen framåt."],org:"3 Mv, tränare. Yta 20×50 m, ett mål. Bollar.",steg:["Mv1 ger speldjup bakåt → passning från tränare.","Mv1 driver + spelvändning till Mv2.","Mv1 ger speldjup bakåt → Mv2 tillbakaspel → Mv1.","Mv1 längre passning till Mv3 som driver mot mållinjen → passar till Mv1.","Spelarna improviserar varianter. Byt position och uppgift."],prog:[],url:"https://ovningsbanken.svenskfotboll.se/fotboll/tranare/ovningsbanken/ovningar/ShowExercise/?exerciseId=96632"},
  "96633":{id:"96633",namn:"Ö2 – Spelövning 1 Speluppbyggnad",typ:"Spelövning",skede:"ANF",kategori:"Speluppbyggnad",principer:["Spelbarhet","Speldjup","Spelvändning"],vad:"Speluppbyggnad",varfor:"Behålla bollen inom laget.",hur:["Spelbarhet: Söka fri yta för att kunna ta emot en passning.","Speldjup: Bollhållaren kan spela bollen både framåt och bakåt.","Spelvändning: Utnyttja ytan motst. lämnar på motsatt kant."],org:"3 Mv + 6 utespelare. 30×20 m, 2 mål. Bollar, koner, västar.",steg:["Lag X vs lag O – håll bollen.","3 Mv med bollhållande laget. 2 Mv vid mål, 1 centralt."],prog:["Erövrar ett lag bollen → mål i valfritt mål. Mv centralt alltid med bollhållande laget."],url:"https://ovningsbanken.svenskfotboll.se/fotboll/tranare/ovningsbanken/ovningar/ShowExercise/?exerciseId=96633"},
  "96634":{id:"96634",namn:"Ö3 – Spelövning 2 Speluppbyggnad",typ:"Spelövning",skede:"ANF",kategori:"Speluppbyggnad",principer:["Spelbarhet","Speldjup","Spelvändning"],vad:"Speluppbyggnad",varfor:"Behålla bollen och skapa överläge centralt.",hur:["Spelbarhet: Erbjud passningsalternativ i alla riktningar.","Speldjup: En spelare ger alltid djuped bakåt och en framåt.","Spelvändning: Vid tät press – finn den öppna sidan snabbt."],org:"4 Mv + 8 utespelare. 40×25 m, 2 mål. Bollar, koner, västar.",steg:["Spel 8 mot 8 – håll bollen.","4 Mv med bollhållande laget, fritt placerade.","Erövrar ett lag bollen → mål i vilket mål som helst."],prog:["Begränsa Mv till kanalerna längs planens sidor."],url:"https://ovningsbanken.svenskfotboll.se/fotboll/tranare/ovningsbanken/ovningar/ShowExercise/?exerciseId=96634"},
  "96636":{id:"96636",namn:"Ö4 – Spelövning 3 Speluppbyggnad",typ:"Spelövning",skede:"ANF",kategori:"Speluppbyggnad",principer:["Spelbarhet","Speldjup","Spelbredd"],vad:"Speluppbyggnad",varfor:"Behålla bollen och ta sig förbi motståndarnas lagdelar.",hur:["Rörelse: Skapa passningsvinklar till bollhållaren.","Värdera och variera: Passningar med ett eller flera tillslag, rätt fart."],org:"3 Mv, 10 utespelare, tränare. 45×30 m, 2 mål. Bollar, koner, västar.",steg:["6 mot 6 + Mv3 som joker med bollhållande laget.","Start: tränaren passar till Mv1 eller Mv2.","Erövrat på motst. halvplan → direkt avslut.","Erövrat på eget halvplan → Mv måste beröra bollen."],prog:[],url:"https://ovningsbanken.svenskfotboll.se/fotboll/tranare/ovningsbanken/ovningar/ShowExercise/?exerciseId=96636"},
  "48347":{id:"48347",namn:"Färdighetsövning – Speluppbyggnad via lagdelar",typ:"Färdighetsövning",skede:"ANF",kategori:"Speluppbyggnad",principer:["Spelbarhet","Speldjup","Spelbredd","Förhindra speluppbyggnad"],vad:"Speluppbyggnad via lagdelar",varfor:"Ta sig förbi motståndarnas lagdelar med kontroll.",hur:["Speluppbyggnad 1: Spela genom motståndarnas lagdelar (speldjup framåt).","Speluppbyggnad 2: Spela utanför motståndarnas lagdelar (spelbredd).","Speluppbyggnad 3: Spela bakåt för att spelvända.","Förhindra: Forward styr mot en sida – laget till bollsida.","Förhindra: Pressa när laget är samlat."],org:"2 lag à 7 spel (6 ut + 1 Mv). Ca 35×20 m.",steg:["1 Mv per kortsida. Varje lag spelar boll från ena Mv till andra.","ALLA spelare i laget måste beröra bollen innan passning till Mv.","Bryt för förberedelseträning med jämna mellanrum."],prog:["Prog 1: Mv varierar höjd och position på passningen.","Prog 2: 2 lag mot varandra. Poäng per komplett kedja utan motst.-beröring."],url:"https://ovningsbanken.svenskfotboll.se/fotboll/tranare/ovningsbanken/ovningar/ShowExercise/?exerciseId=48347"},
  "96618":{id:"96618",namn:"Ö1 – Förberedelseträning Djupledsspel",typ:"Färdighetsövning",skede:"ANF",kategori:"Djupledsspel",principer:["Djupledsspel","Förhindra avslut"],vad:"Förhindra och rädda avslut",varfor:"Förhindra att det blir mål.",hur:["Position: Starta några meter framför mållinjen med det ena benet framför det andra.","Fånga: I steget med ena benet framför det andra.","Täcka spelyta 3: Komma ut i rätt läge för att hindra djuppassning."],org:"3 Mv, tränare. Yta 20×20 m, ett mål. Bollar och koner.",steg:["Tränaren spelar bollen i djupled mot Mv1.","Mv1 löper mot bollen och fångar den.","Om Mv får bollen utanför straffområdet passar hen till Mv3 som förflyttar sig åt olika håll.","Mv3 spelar tillbaka till tränaren. Rotation: Mv1→Mv2→Mv3."],prog:["Tränaren varierar djupet och riktningen på passningen."],url:"https://ovningsbanken.svenskfotboll.se/fotboll/tranare/ovningsbanken/ovningar/ShowExercise/?exerciseId=96618"},
  "96621":{id:"96621",namn:"Ö4 – Spelövning 1 Djupledsspel och frilägen",typ:"Spelövning",skede:"ANF",kategori:"Djupledsspel",principer:["Djupledsspel","Komma till avslut","Förhindra avslut"],vad:"Djupledsspel / Förhindra avslut",varfor:"Skapa genombrott och frilägen. Förhindra mål.",hur:["Löptiming: Starta löpningen strax innan bollen spelas.","Blockteknik: Nära motsp., böja knän, ben tätt, armar längs kroppen.","Palming: Stöta bort med en eller båda händerna."],org:"3 Mv + 6 utespelare. 30×20 m, 2 mål.",steg:["Mv1 spelar bollen till anfallare.","4 mot 2: anfallarna spelar in bollen bakom försvararna.","Försvarare erövrar → kontring mot Mv3. Anfallare återerövrar.","Ny passning från Mv1. Mv byter uppgifter."],prog:["En försvarsspelare får följa med ner i försvarszonen."],url:"https://ovningsbanken.svenskfotboll.se/fotboll/tranare/ovningsbanken/ovningar/ShowExercise/?exerciseId=96621"},
  "96622":{id:"96622",namn:"Ö5 – Spelövning 2 Djupledsspel och frilägen",typ:"Spelövning",skede:"ANF",kategori:"Djupledsspel",principer:["Djupledsspel","Komma till avslut","Förhindra djupledsspel"],vad:"Djupledsspel och frilägen",varfor:"Skapa och utnyttja frilägen i djupled.",hur:["Position: Täcka motståndarnas spelyta 3.","Löptiming: Starta löpningen strax innan bollen spelas.","Passningstiming: Passa med tillräcklig fart för löpande spelare."],org:"2 Mv, 10 utespelare. 30×35 m, 2 mål.",steg:["Planen delas in i tre zoner.","Mv1 spelar bollen till en medspelare.","Spel 5 mot 5 i central zon. Anfallande laget skapar djupledsspel och frilägen.","När försvaret erövrar bollen → omst. till försvar direkt."],prog:["Neutral Mv3 centralt som alltid spelar med bollhållande laget."],url:"https://ovningsbanken.svenskfotboll.se/fotboll/tranare/ovningsbanken/ovningar/ShowExercise/?exerciseId=96622"},
  "96620":{id:"96620",namn:"Ö3 – Blockera skott vid avslut",typ:"Färdighetsövning",skede:"FORS",kategori:"Förhindra avslut",principer:["Förhindra avslut","Blockera skott"],vad:"Förhindra och rädda avslut",varfor:"Förhindra att det blir mål.",hur:["Position: Starta några meter framför mållinjen.","Blockteknik: Nära motspelaren, böja knän, ben tätt, armar längs kroppen.","Palming: Stöta bort bollen från målet."],org:"3 Mv. Yta 15×10 m med ett mål. Bollar.",steg:["Mv2 spelar bollen mot Mv1 och följer efter.","Mv1 förflyttar sig snabbt framför konmålet.","Mv2 avslutar – Mv1 blockerar.","Mv2 → ny Mv. Mv3 → utespelare. Mv1 vilar."],prog:[],url:"https://ovningsbanken.svenskfotboll.se/fotboll/tranare/ovningsbanken/ovningar/ShowExercise/?exerciseId=96620"},
  "96619":{id:"96619",namn:"Ö2 – Blockera avslut vid friläge",typ:"Färdighetsövning",skede:"FORS",kategori:"Förhindra avslut",principer:["Förhindra avslut","Blockera skott"],vad:"Förhindra och rädda avslut",varfor:"Förhindra att det blir mål.",hur:["Position: Starta några meter framför mållinjen.","Blockteknik: Nära motspelaren, böja knän, ben tätt, armar längs kroppen.","Om dribbel: Följa med i rörelsen, kasta sig framåt mot bollen."],org:"3 Mv, tränare. Yta 10×10 m, 2 konmål. Bollar.",steg:["Tränare spelar mot Mv1. Mv1 löper + avslutar. Mv2 blockerar.","Mv3 spelar mot Mv1 → upprepas. Mv2 → ny Mv."],prog:["Variant 1: Tränare spelar så Mv1+Mv2 har lika chans.","Variant 2: Mv1 kan välja avslut eller dribbling förbi Mv2."],url:"https://ovningsbanken.svenskfotboll.se/fotboll/tranare/ovningsbanken/ovningar/ShowExercise/?exerciseId=96619"},
  "96683":{id:"96683",namn:"Ö1 – Förberedelseträning Skott",typ:"Färdighetsövning",skede:"FORS",kategori:"Skott & avslut",principer:["Förhindra avslut","Blockera skott"],vad:"Förhindra och rädda avslut",varfor:"Förhindra att det blir mål.",hur:["Lägre bollar: Händerna under bollen, fånga mellan underarmar och kropp.","Högre bollar: Möt med händerna, greppa framför kroppen.","Sidabollar: Flytta i sidled och kom bakom bollen."],org:"3 Mv. 3 konmål med 15 m mellanrum.",steg:["Mv1 skjuter till Mv2 som fångar. Mv1 följer bollen.","Mv2 vänder + volley till Mv3 som fångar.","Mv2 tar Mv1:s position. Rotation pågår."],prog:[],url:"https://ovningsbanken.svenskfotboll.se/fotboll/tranare/ovningsbanken/ovningar/ShowExercise/?exerciseId=96683"},
  "96684":{id:"96684",namn:"Ö2 – Färdighetsövning 1 Skott",typ:"Färdighetsövning",skede:"FORS",kategori:"Skott & avslut",principer:["Förhindra avslut","Blockera skott"],vad:"Förhindra och rädda avslut",varfor:"Förhindra att det blir mål.",hur:["Position: Sidledsförflyttning för att komma bakom bollen.","Lägre bollar: Händerna under, fånga mellan underarmar och kropp.","Högre bollar: Händerna framför kroppen, greppa."],org:"3 Mv, tränare. Yta 15×15 m, ett mål. Bollar, koner.",steg:["Tränare passar – Mv anpassar sidledsposition.","X1 löper mot bollen + avslutar mot Mv.","Tränare passar till X2. Byt Mv."],prog:[],url:"https://ovningsbanken.svenskfotboll.se/fotboll/tranare/ovningsbanken/ovningar/ShowExercise/?exerciseId=96684"},
  "96608":{id:"96608",namn:"Ö3 – Färdighetsövning 2 Skott",typ:"Färdighetsövning",skede:"FORS",kategori:"Skott & avslut",principer:["Förhindra avslut","Blockera skott"],vad:"Förhindra och rädda avslut",varfor:"Förhindra att det blir mål.",hur:["Fånga lägre bollar: Hålla händerna under bollen och fånga den mellan underarmarna och kroppen.","Höga bollar: Möta bollen med händerna och greppa den framför kroppen.","Reaktion vid skarv: Anpassa positionen när tränaren skarvar."],org:"4 Mv, tränare. Yta 15×15 m, ett mål. Bollar.",steg:["X1 passar till tränaren som skarvar bollen i djupled.","X1 löper efter bollen och avslutar mot Mv1.","Därefter spelar Mv2 och X2.","De som avslutat byter uppgift med målvakterna efter fyra avslut."],prog:["Variera djupet och vinkeln på skarven."],url:"https://ovningsbanken.svenskfotboll.se/fotboll/tranare/ovningsbanken/ovningar/ShowExercise/?exerciseId=96608"},
  "96609":{id:"96609",namn:"Ö4 – Färdighetsövning 3 Skott",typ:"Färdighetsövning",skede:"FORS",kategori:"Skott & avslut",principer:["Förhindra avslut","Blockera skott"],vad:"Förhindra och rädda avslut",varfor:"Förhindra att det blir mål.",hur:["Position: Anpassa positionen till medspelaren som täcker eller blockerar avslutet.","Kommunikation: Ropa ut 'mine' eller 'blockera' tydligt.","Reaktion: Reagera på bollens riktning i rätt ögonblick."],org:"4 Mv. Yta 12×12 m, 2 mål. Bollar.",steg:["Planen delas in i tre zoner med 4 m djup och spelarna i par.","Mv1 rullar ut bollen till sin medspelare som driver + avslutar i egen försvarszon mot Mv2.","Försvarsspelaren hjälper Mv2 att blockera/rädda avslutet.","Rotation efter varje avslut."],prog:["Bollhållaren får välja om hen dribblar vidare eller avslutar direkt."],url:"https://ovningsbanken.svenskfotboll.se/fotboll/tranare/ovningsbanken/ovningar/ShowExercise/?exerciseId=96609"},
  "96611":{id:"96611",namn:"Ö5 – Spelövning 1 Skott",typ:"Spelövning",skede:"FORS",kategori:"Skott & avslut",principer:["Förhindra avslut","Blockera skott","Återerövring"],vad:"Förhindra och rädda avslut",varfor:"Förhindra mål i matchnära situationer.",hur:["Position: Anpassa positionen till bollen, medspelare och motspelare.","Täcka: Stäng av avslutsytan utan att begå foul.","Kommunikation: Mv ropar 'mine' eller 'out' tydligt."],org:"2 Mv, 6 utespelare. Yta 20×20 m, 2 mål.",steg:["Spel 3 mot 1 på respektive planhalva.","Lagen ska avsluta med skott på egen planhalva.","Om medspelaren erövrar bollen eller tar den vid retur → avslut på motståndarnas planhalva."],prog:["Begränsa utespelarna till 2 touch."],url:"https://ovningsbanken.svenskfotboll.se/fotboll/tranare/ovningsbanken/ovningar/ShowExercise/?exerciseId=96611"},
  "96613":{id:"96613",namn:"Ö6 – Spelövning 2 Skott",typ:"Spelövning",skede:"FORS",kategori:"Skott & avslut",principer:["Förhindra avslut","Blockera skott","Återerövring"],vad:"Förhindra och rädda avslut",varfor:"Förhindra mål och skapa omst.→anfall.",hur:["Position: Anpassa positionen till bollen, medspelare och motspelare.","Täcka: Stäng av avslutsytan tidigt.","Kontra: Erövrar man boll → kontra direkt."],org:"2 Mv, 6 utespelare. Yta 25×15 m, 2 mål.",steg:["Spel 4 mot 4.","Uppmuntra spelarna att avsluta så ofta som möjligt."],prog:["Avslutskrav: laget måste avsluta inom 10 sek."],url:"https://ovningsbanken.svenskfotboll.se/fotboll/tranare/ovningsbanken/ovningar/ShowExercise/?exerciseId=96613"},
  "89741":{id:"89741",namn:"Ö1 – Förberedelseträning Blockera avslut vid frilägen",typ:"Färdighetsövning",skede:"FORS",kategori:"Förhindra avslut",principer:["Förhindra avslut","Blockera skott"],vad:"Förhindra och rädda avslut",varfor:"Förhindra att det blir avslut.",hur:["Position: Starta några meter framför mållinjen med det ena benet framför det andra.","Timing: Röra sig framåt när anfallaren tar sista steget mot bollen.","Blockteknik: Nära motspelaren, böja knän, ben tätt, armar längs kroppen."],org:"4 Mv, tränare. Yta 20×20 m, ett mål. Bollar och koner.",steg:["Tränaren spelar bollen mot målet.","Mv1 bryter djupledspassningen och fångar bollen.","Om Mv når bollen utanför straffområdet passar hen tillbaka till tränaren.","Rotation: Mv1→Mv2→Mv3→Mv4."],prog:["Tränaren varierar riktningen och höjden på passningen."],url:"https://ovningsbanken.svenskfotboll.se/fotboll/tranare/ovningsbanken/ovningar/ShowExercise/?exerciseId=89741"},
  "89742":{id:"89742",namn:"Ö2 – Färdighetsövning 1 Blockera avslut vid frilägen",typ:"Färdighetsövning",skede:"FORS",kategori:"Förhindra avslut",principer:["Förhindra avslut","Blockera skott"],vad:"Förhindra och rädda avslut",varfor:"Förhindra att det blir mål.",hur:["Position: Starta några meter framför mållinjen.","Timing: Röra sig när anfallaren tar sista steget.","Om dribbel: Följa med i rörelsen och kasta sig framåt mot bollen."],org:"4 Mv. Yta 20×25 m, ett mål. Bollar och koner.",steg:["Bollhållaren driver bollen snabbt mot mål.","Mv1 möter bollhållaren som avslutar från kort avstånd.","Mv1 blockerar avslutet.","Därefter driver nästa bollhållare mot Mv2.","Variant: Bollhållaren försöker dribbla förbi Mv."],prog:["Bollhållaren bestämmer om hen avslutar eller dribblar."],url:"https://ovningsbanken.svenskfotboll.se/fotboll/tranare/ovningsbanken/ovningar/ShowExercise/?exerciseId=89742"},
  "96685":{id:"96685",namn:"Ö3 – Färdighetsövning 2 Skott (kantavslut)",typ:"Färdighetsövning",skede:"FORS",kategori:"Skott & avslut",principer:["Förhindra avslut","Komma till avslut"],vad:"Förhindra och rädda avslut",varfor:"Förhindra att det blir mål.",hur:["Sidoledsförflyttning kombinerat med framåtrörelser.","Täck närmaste stolpen vid krosspass.","Reaktion: reagera på bollens riktning i rätt ögonblick."],org:"3 Mv, tränare. Yta 20×15 m, ett mål. Bollar, koner.",steg:["Tränare passar till X1 på kanten.","X1 driver inåt och avslutar – Mv anpassar position.","X2 startar från andra kanten. Byt Mv efter 4 avslut."],prog:["Lägg till en defensiv spelare som halvpassivt försöker blockera."],url:"https://ovningsbanken.svenskfotboll.se/fotboll/tranare/ovningsbanken/ovningar/ShowExercise/?exerciseId=96685"},
  "96606":{id:"96606",namn:"Ö1 – Förberedelseträning Skott (4 Mv)",typ:"Färdighetsövning",skede:"FORS",kategori:"Skott & avslut",principer:["Förhindra avslut"],vad:"Förhindra och rädda avslut",varfor:"Förhindra att det blir mål.",hur:["Lägre bollar: Hålla händerna under bollen och fånga den mellan underarmarna och kroppen.","Högre bollar: Möta bollen med händerna och greppa den framför kroppen.","Bollar vid sidan av målvakten: Flytta i sidled och komma bakom bollen."],org:"Fyra målvakter; yta 18 x 12 meter; bollar och koner.",steg:["Målvakterna rör sig fritt i ytan.","Bollhållaren spelar bollen till någon av de andra som fångar bollen, lägger ner den på marken och passar vidare.","Bollen kan spelas i en bestämd eller valfri turordning.","När en målvakt har spelat bollen rundar hen en valfri kon, dock inte den närmaste.","Uppmana spelarna att variera höjden på bollarna: bollar på marken, låga bollar i luften och höga bollar mot kroppen."],prog:[],url:"https://ovningsbanken.svenskfotboll.se/fotboll/tranare/ovningsbanken/ovningar/ShowExercise/?exerciseId=96606"},
  "96607":{id:"96607",namn:"Ö2 – Färdighetsövning 1 Skott (kastning)",typ:"Färdighetsövning",skede:"FORS",kategori:"Skott & avslut",principer:["Förhindra avslut"],vad:"Förhindra och rädda avslut",varfor:"Förhindra att det blir mål.",hur:["Position: Sidledsförflyttning efter bollens position, i balans vid avslut.","Fånga lägre bollar: Hålla händerna under bollen och fånga den mellan underarmarna och kroppen.","Fånga högre bollar: Möta bollen med händerna och greppa den framför kroppen.","Kasta sig och fånga lägre bollar: Landa på sidan med kroppen bakom bollen, möta bollen med båda händerna.","Kasta sig och fånga högre bollar: Frånskjut med foten närmast bollen.","Palming: Stöta iväg bollen med öppen hand mot långsidan."],org:"Fyra målvakter, du som tränare; yta 15 x 20 meter med ett mål; bollar och koner.",steg:["Mv1 står i rätt position i förhållande till bollhållaren.","Du som tränare passar till X1 som tar emot bollen och avslutar.","Mv1 gör en sidledsförflyttning och räddar avslutet.","Därefter spelar X2 och Mv2.","Målvakterna byter uppgift med utespelarna efter fyra avslut per målvakt.","Inledningsvis skjuter den som avslutar så att målvakten kan rädda utan att kasta sig.","Därefter skjuter avslutaren skott något vid sidan om målvakten så att hen måste kasta sig."],prog:["Du som tränare passar till valfri utespelare som avslutar på första tillslaget."],url:"https://ovningsbanken.svenskfotboll.se/fotboll/tranare/ovningsbanken/ovningar/ShowExercise/?exerciseId=96607"},
  "96686":{id:"96686",namn:"Ö4 – Färdighetsövning 3 Skott (10 utespelaren)",typ:"Färdighetsövning",skede:"FORS",kategori:"Skott & avslut",principer:["Förhindra avslut","Blockera skott"],vad:"Förhindra och rädda avslut",varfor:"Förhindra att det blir mål.",hur:["Position: Sidledsförflyttning efter bollens position, i balans vid avslut.","Fånga lägre bollar: Fånga mellan underarmar och kropp.","Fånga höga bollar: Möta bollen med händerna framför kroppen.","Kasta sig: Frånskjut med foten närmast bollen.","Palming: Stöta iväg bollen med öppen hand.","Blockteknik: Komma nära motspelaren, böja knäna, ha benen nära varandra."],org:"Tre målvakter, tio utespelare; yta 25 x 20 meter med två mål; bollar och koner.",steg:["Spel 5 mot 5 med Mv i varje mål.","Avslutsövning: spel med avslutskrav, laget måste avsluta inom 10 sek.","Mv agerar för att förhindra eller rädda avsluten.","Byt Mv efter tre minuter."],prog:["Reducera avslutskravet till 7 sek."],url:"https://ovningsbanken.svenskfotboll.se/fotboll/tranare/ovningsbanken/ovningar/ShowExercise/?exerciseId=96686"},
  "96687":{id:"96687",namn:"Ö5 – Spelövning 1 Skott (joker)",typ:"Spelövning",skede:"FORS",kategori:"Skott & avslut",principer:["Förhindra avslut","Blockera skott","Återerövring"],vad:"Förhindra och rädda avslut",varfor:"Förhindra att det blir mål.",hur:["Position: Anpassa positionen till bollen, medspelarna och motspelarna.","Kommunikation: Styra medspelarna så att de täcker eller markerar.","Upphopp: Attackera bollen med fart, upphopp på ett ben eller jämfota.","Komma före motspelaren till bollen.","Fånga bollen: Fånga bollen så tidigt och så högt som möjligt.","Boxa bollen: Träffa bollen snett underifrån.","Blockteknik: Komma nära motspelaren, böja knäna.","Palming: Stöta iväg bollen med öppen hand."],org:"Tre målvakter, tio utespelare (varav två jokrar som startar i mittzonen); spelplan 40 x 60 meter; bollar, koner och västar.",steg:["Spel 4 mot 4 på varje planhalva.","Jokrarna spelar med det anfallande laget.","Anfallsspelarna ska avsluta på motst. planhalva.","Mv agerar för att förhindra eller rädda avsluten.","Byt jokrar efter tre minuter."],prog:["Reducera till en joker."],url:"https://ovningsbanken.svenskfotboll.se/fotboll/tranare/ovningsbanken/ovningar/ShowExercise/?exerciseId=96687"},
  "96692":{id:"96692",namn:"Ö1 – Förberedelseträning Inlägg",typ:"Färdighetsövning",skede:"ANF",kategori:"Inlägg",principer:["Inlägg & avslut","Komma till avslut"],vad:"Förhindra och rädda avslut",varfor:"Förhindra att det blir mål.",hur:["Position: Centralt i målet och halvt vänd mot bollen.","Upphopp: Attackera bollen med fart, upphopp på ett ben eller jämfota.","Komma före motspelaren till bollen.","Fånga bollen: Fånga bollen så tidigt och så högt som möjligt."],org:"Tre målvakter; yta 18 x 50 meter med två mål; bollar.",steg:["Mv1 och Mv2 passar bollen till varandra.","Mv3 agerar som kantspelare och slår inlägg mot Mv1 eller Mv2.","Mv1 eller Mv2 agerar som anfallare och försöker avsluta på Mv3:s mål.","Byt roller var tredje minut."],prog:["Lägg till en medspelare som anfallare i straffområdet."],url:"https://ovningsbanken.svenskfotboll.se/fotboll/tranare/ovningsbanken/ovningar/ShowExercise/?exerciseId=96692"},
  "96693":{id:"96693",namn:"Ö2 – Färdighetsövning 1 Inlägg",typ:"Färdighetsövning",skede:"ANF",kategori:"Inlägg",principer:["Inlägg & avslut","Komma till avslut"],vad:"Förhindra och rädda avslut",varfor:"Förhindra att det blir mål.",hur:["Position: Centralt i målet och halvt vänd mot bollen.","Upphopp: Attackera bollen med fart, upphopp på ett ben eller jämfota.","Komma före motspelaren till bollen.","Fånga bollen: Fånga bollen så tidigt och så högt som möjligt.","Boxa bollen: Träffa bollen snett underifrån."],org:"Tre målvakter, du som tränare; yta 15 x 55 meter med ett mål; bollar.",steg:["Bollhållaren spelar bollen till medspelaren på kanten.","Målvakten korrigerar sin position i förhållande till bollhållaren.","Spelaren på kanten kan välja att slå ett tidigt eller sent inlägg.","Medspelaren agerar för att avsluta.","Målvakten agerar för att förhindra eller rädda avslutet.","Spelaren som avslutar och målvakten byter uppgifter."],prog:[],url:"https://ovningsbanken.svenskfotboll.se/fotboll/tranare/ovningsbanken/ovningar/ShowExercise/?exerciseId=96693"},
  "96694":{id:"96694",namn:"Ö3 – Spelövning 1 Inlägg",typ:"Spelövning",skede:"ANF",kategori:"Inlägg",principer:["Inlägg & avslut","Komma till avslut","Kontra snabbt"],vad:"Förhindra och rädda avslut",varfor:"Förhindra att det blir mål.",hur:["Position: Anpassa positionen till bollen medspelarna och motspelarna.","Kommunikation: Styra medspelarna så att de täcker eller markerar.","Upphopp: Attackera bollen med fart, upphopp på ett ben eller jämfota.","Komma före motspelaren till bollen.","Fånga bollen: Fånga bollen så tidigt och så högt som möjligt.","Boxa bollen: Träffa bollen snett underifrån.","Blockteknik: Komma nära motspelaren, böja knäna."],org:"Tre målvakter, åtta utespelare; spelplan 30 x 50 meter med två mål; bollar, koner och västar.",steg:["Mv1 passar bollen till Mv2 som spelar ut den till kantspelaren.","Kantspelaren driver bollen och kan välja att slå ett tidigt eller sent inlägg.","I straffområdet finns Mv3 och en utespelare som ska försvara.","Anfallsspelarna ska försöka göra mål.","Om Mv3 fångar bollen ska hen kasta bollen till Mv1.","Om försvarsspelaren bryter ska hen passa bollen till Mv1."],prog:["Variant 1: Om Mv3 eller försvarsspelaren bryter kan laget kontra.","Variant 2: Kantspelaren kan driva in bollen i straffområdet."],url:"https://ovningsbanken.svenskfotboll.se/fotboll/tranare/ovningsbanken/ovningar/ShowExercise/?exerciseId=96694"},
  "96695":{id:"96695",namn:"Ö4 – Spelövning 2 Inlägg",typ:"Spelövning",skede:"ANF",kategori:"Inlägg",principer:["Inlägg & avslut","Komma till avslut"],vad:"Förhindra och rädda avslut",varfor:"Förhindra att det blir mål.",hur:["Position: Anpassa positionen till bollen medspelarna och motspelarna.","Kommunikation: Styra medspelarna så att de täcker eller markerar.","Upphopp: Attackera bollen med fart, upphopp på ett ben eller jämfota.","Fånga bollen: Fånga bollen så tidigt och så högt som möjligt.","Boxa bollen: Träffa bollen snett underifrån.","Blockteknik: Komma nära motspelaren, böja knäna.","Palming: Stöta iväg bollen."],org:"Tre målvakter, tolv utespelare; spelplan 30 x 50 meter med två mål; bollar, koner och västar.",steg:["Mv1 slår ett inlägg mot Mv2 som fångar bollen.","Mv2 gör ett utkast till någon av kantspelarna på motståndarnas planhalva.","Kantspelaren slår ett inlägg mot Mv3 som försvarar tillsammans med de båda backarna.","Forwards och vänster kantspelare går på avslut.","Spelet fortsätter tills det blir mål eller tills bollen är utanför planen.","Om Mv3 fångar bollen gör hen ett utkast till en av kantspelarna."],prog:[],url:"https://ovningsbanken.svenskfotboll.se/fotboll/tranare/ovningsbanken/ovningar/ShowExercise/?exerciseId=96695"},
  "89743":{id:"89743",namn:"Ö3 – Färdighetsövning 2 Blockera avslut vid frilägen",typ:"Färdighetsövning",skede:"FORS",kategori:"Förhindra avslut",principer:["Förhindra avslut","Blockera skott"],vad:"Förhindra och rädda avslut",varfor:"Förhindra att det blir mål.",hur:["Position: Starta några meter framför mållinjen.","Blockteknik: Komma nära motspelaren, böja knäna, ha benen nära varandra och hålla armarna längs kroppen."],org:"Fyra målvakter, du som tränare; yta 20 x 25 meter med ett mål; bollar och koner.",steg:["Du som tränare passar bollen mot mål.","X1 löper i djupled och avslutar.","Mv1 rör sig framåt för att blockera avslutet.","Du passar till X2 som löper och avslutar mot Mv2.","Byt uppgifter efter fyra upprepningar per målvakt."],prog:[],url:"https://ovningsbanken.svenskfotboll.se/fotboll/tranare/ovningsbanken/ovningar/ShowExercise/?exerciseId=89743"},
  "89744":{id:"89744",namn:"Ö4 – Färdighetsövning 3 Djupledsspel och frilägen",typ:"Färdighetsövning",skede:"ANF",kategori:"Djupledsspel",principer:["Djupledsspel","Förhindra avslut"],vad:"Förhindra och rädda avslut",varfor:"Förhindra att det blir mål.",hur:["Position: Starta några meter framför mållinjen.","Fånga bollen: Fånga bollen i steget med det ena benet framför det andra.","Kasta sig och fånga bollen: Landa på sidan och möta bollen framför kroppen.","Blockteknik: Komma nära motspelaren, böja knäna, ha benen nära varandra och hålla armarna längs kroppen.","Palming: Stöta bort bollen från målet med en hand eller båda händerna."],org:"Fyra målvakter; yta 20 x 20 meter med två mål; bollar och koner.",steg:["Målvaktsmatch.","Bollhållaren och medspelaren passar bollen till varandra på egen planhalva.","En av spelarna slår en djupledspassning in på motståndarnas planhalva.","Medspelaren avslutar på första tillslaget eller försöker dribbla förbi målvakten.","Mv1 strävar efter att förhindra eller rädda avslutet.","Spelarna inom paren byter uppgift efter fyra avslut."],prog:[],url:"https://ovningsbanken.svenskfotboll.se/fotboll/tranare/ovningsbanken/ovningar/ShowExercise/?exerciseId=89744"},
  "89745":{id:"89745",namn:"Ö5 – Spelövning 1 Djupledsspel och frilägen",typ:"Spelövning",skede:"ANF",kategori:"Djupledsspel",principer:["Djupledsspel","Komma till avslut"],vad:"Förhindra och rädda avslut",varfor:"Förhindra att det blir mål.",hur:["Position: Täcka ytan framför medspelarna.","Fånga bollen: Fånga bollen i steget med det ena benet framför det andra.","Kasta sig och fånga bollen: Landa på sidan och möta bollen framför kroppen.","Blockteknik: Komma nära motspelaren, böja knäna, ha benen nära varandra och hålla armarna längs kroppen.","Palming: Stöta bort bollen från målet med en hand eller båda händerna.","Benparad: Flytta ena benet i sidled och rädda avslutet med foten eller benet."],org:"Två målvakter, åtta utespelare; spelplan 30 x 25 meter med två mål; bollar, koner och västar.",steg:["Spel 4 mot 4 i mittzonen.","Bollhållaren passar bollen till en medspelare som löper in i anfallszonen för att avsluta.","Ingen motspelare får följa med in i försvarszonen."],prog:["Bollhållaren får själv driva eller dribbla in i anfallszonen och avsluta.","En motspelare får följa med och försvara.","Bollhållaren får skjuta från mittzonen."],url:"https://ovningsbanken.svenskfotboll.se/fotboll/tranare/ovningsbanken/ovningar/ShowExercise/?exerciseId=89745"},
};

